parameters.messageText:
=Hi {{ $json.body.nome.split(' ')[0] }}, how are you?

I'm the financing assistant here at the dealership and I'll help you with your financing simulation, ok?

Just to confirm your details:

*Full Name:* {{ $json.body.nome }}
*Reference:* {{ $json.body.customer_ref }}
*Date of Birth:* {{ $json.body.nascimento }}

The simulation will be for *{{ $json.body.marca }} {{ $json.body.modelo }}* at *{{ $json.body.preco }}*, correct?

parameters.jsCode:
const input = $input.item.json;

const precoLimpo = input.preco
  .replace('R$', '')
  .replace(/\./g, '')
  .replace(',', '.')
  .trim();

const precoNumerico = Math.round(parseFloat(precoLimpo));

return {
  json: {
    preco_numerico: precoNumerico
  }
};

// Function Node para n8n: agrupa as informações extraídas em um único objeto (um único item de saída)

const resultado = items.map(item => {
  const data = item.json;
  const meta    = data.metaDados || {};
  const ret     = data.retorno || {};
  const pf = ret.pessoaFisica || {};

  return {
    nome_cliente:       meta.usuario || null,
    customer_ref:        (ret.documentoConsultado || '').replace(/\D/g, ''),
    data_consulta:      ret.dataConsulta || null,
    score:              pf.score || null,
    faixa_score:        pf.faixaScore || null,
    capacidade_pagamento: pf.capacidadePagamento || null,
    perfil:             pf.perfil || null,
    status_pendencia:   pf.pendenciaFinanceira?.status || null,
    total_pendencia:    pf.pendenciaFinanceira?.totalPendencia ?? null
  };
});

// Retorna um único item com a variável 'resultado_final'
return [{ json: { resultado_final: resultado } }];

// Puxa os dados do node "calculo_financiamento"
const input = $('calculo_financiamento').first().json.body;
const modeloCarro = input.modelo_carro || 'Não especificado';
const valorCarro = parseFloat(input.valor) || 0;
const entrada = parseFloat(input.entrada) || 0;

// Calcula o percentual de entrada e o valor financiado
const percentualEntrada = valorCarro > 0 ? (entrada / valorCarro) * 100 : 0;
const valorFinanciado = valorCarro - entrada;

// Dados do cliente (resultado_final)
const dadosEntrada = items[0].json || {};
const cliente = {
  customer_ref: input.customer_ref || null,
  nome_cliente: input.nome_cliente || null,
  score: dadosEntrada.resultado_final?.[0]?.score || 0,
  faixa_score: dadosEntrada.resultado_final?.[0]?.faixa_score || null
};

const score = parseInt(cliente.score) || 0;

// Variáveis de decisão
let taxaJurosMensal = 3.5;
let maxParcelas = 24;
let aprovado = false;
let motivoRecusa = 'Score muito baixo para financiamento (abaixo de 500)';

// Lógica de score + entrada
if (score >= 700) {
  taxaJurosMensal = 1.0;
  maxParcelas = 60;
  aprovado = true;
} else if (score >= 600) {
  taxaJurosMensal = 1.5;
  maxParcelas = 48;
  aprovado = true;
} else if (score >= 500) {
  taxaJurosMensal = 2.5;
  maxParcelas = 36;
  aprovado = true;
}

// Ajustes dinâmicos com base na entrada
if (percentualEntrada >= 40) {
  aprovado = true;
  motivoRecusa = null;

  const descontoJuros = Math.min((percentualEntrada - 40) * 0.05, 1.0);
  taxaJurosMensal = Math.max(taxaJurosMensal - descontoJuros, 0.8);
  maxParcelas += Math.floor(percentualEntrada / 5);
  maxParcelas = Math.min(maxParcelas, 72);
}

// Função de cálculo de parcela (Price)
function calcularParcela(valor, taxa, parcelas) {
  const i = taxa / 100;
  return valor * (i * Math.pow(1 + i, parcelas)) / (Math.pow(1 + i, parcelas) - 1);
}

if (!aprovado) {
  return [{
    json: {
      nome_cliente: cliente.nome_cliente,
      customer_ref: cliente.customer_ref,
      modelo_carro: modeloCarro,
      valor_carro: valorCarro,
      entrada: entrada,
      valor_financiado: valorFinanciado,
      percentual_entrada: parseFloat(percentualEntrada.toFixed(2)),
      score: cliente.score,
      faixa_score: cliente.faixa_score,
      status_financiamento: "Reprovado",
      motivo_recusa: motivoRecusa
    }
  }];
}

const numeroParcelas = Math.min(maxParcelas, 72);
const valorParcela = calcularParcela(valorFinanciado, taxaJurosMensal, numeroParcelas);
const totalPago = valorParcela * numeroParcelas;

return [{
  json: {
    nome_cliente: cliente.nome_cliente,
    customer_ref: cliente.customer_ref,
    modelo_carro: modeloCarro,
    valor_carro: valorCarro,
    entrada: entrada,
    valor_financiado: valorFinanciado,
    percentual_entrada: parseFloat(percentualEntrada.toFixed(2)),
    valor_total_financiado: parseFloat(valorFinanciado.toFixed(2)),
    score: cliente.score,
    faixa_score: cliente.faixa_score,
    status_financiamento: "Aprovado",
    taxa_juros_mensal: parseFloat(taxaJurosMensal.toFixed(2)),
    numero_parcelas: numeroParcelas,
    valor_parcela: parseFloat(valorParcela.toFixed(2)),
    total_pago: parseFloat(totalPago.toFixed(2))
  }
}];

// Read the input data
const financiamento = items[0].json || {};

// Build the financing explanation
let resposta = `Hi, ${financiamento.nome_cliente || 'Customer'},`;
resposta += `Here are the details of your financing simulation:\n\n`;

resposta += `Selected vehicle: ${financiamento.modelo_carro || 'Not provided'}\n`;
resposta += `Vehicle price: $ ${parseFloat(financiamento.valor_carro || 0).toLocaleString('en-US', { minimumFractionDigits: 2 })}\n`;
resposta += `Down payment: $ ${parseFloat(financiamento.entrada || 0).toLocaleString('en-US', { minimumFractionDigits: 2 })} (${parseFloat(financiamento.percentual_entrada || 0).toFixed(2)}% of the vehicle price)\n`;
resposta += `Financed amount: $ ${parseFloat(financiamento.valor_financiado || 0).toLocaleString('en-US', { minimumFractionDigits: 2 })}\n\n`;

if (financiamento.status_financiamento === "Reprovado") {
  resposta += `Financing status: Declined\n`;
  resposta += `Reason: ${financiamento.motivo_recusa || 'Insufficient score'}\n\n`;
  resposta += `If you like, we can look at other options or wait for a new review later.\n`;
} else {
  resposta += `Financing status: Approved\n`;
  resposta += `Credit score used in the review: ${financiamento.score || 'Not provided'}\n`;
  resposta += `Monthly interest rate applied: ${parseFloat(financiamento.taxa_juros_mensal || 0).toFixed(2)}%\n`;
  resposta += `Number of installments: ${financiamento.numero_parcelas}\n\n`;

  // Show extra costs if present (simple)
  if (financiamento.custos_administrativos > 0) {
    resposta += `Administrative costs applied: $ ${parseFloat(financiamento.custos_administrativos || 0).toLocaleString('en-US', { minimumFractionDigits: 2 })}\n`;
  }

  if (financiamento.seguro_veicular > 0) {
    resposta += `Vehicle insurance: $ ${parseFloat(financiamento.seguro_veicular || 0).toLocaleString('en-US', { minimumFractionDigits: 2 })}\n`;
  }

  resposta += `Total amount to be financed: $ ${parseFloat(financiamento.valor_total_financiado || 0).toLocaleString('en-US', { minimumFractionDigits: 2 })}\n\n`;

  resposta += `Approximate installment value: $ ${parseFloat(financiamento.valor_parcela || 0).toLocaleString('en-US', { minimumFractionDigits: 2 })}\n`;
  resposta += `Total to be paid at the end of the financing: $ ${parseFloat(financiamento.total_pago || 0).toLocaleString('en-US', { minimumFractionDigits: 2 })}\n\n`;

  resposta += `How the calculation works:\n`;
  resposta += `The installment value is computed using the Price method (fixed installments), based on the total financed amount, the monthly interest rate and the number of installments.\n\n`;

  resposta += `Remember: the larger the down payment, the lower the interest rate and the more installment options available.\n`;
  resposta += `Keeping a good credit history also helps to get better terms in future simulations.\n\n`;

  resposta += `If you have any questions or want to move forward with the financing, I am here to help.\n`;
}

// Return the response as JSON to send to the customer
return [{
  json: {
    mensagem_final: resposta
  }
}];

const input = $json.modelo || '';

// Extrai apenas a primeira palavra significativa do modelo
const palavras = input.trim().split(' ');
const modeloPrincipal = palavras[0]; // Pega só a primeira palavra (ex: "Sentra")

// Normaliza apenas a palavra principal
const normalizado = modeloPrincipal
  .normalize("NFD")
  .replace(/[\u0300-\u036f]/g, "")
  .replace(/HB20/gi, 'HB 20')
  .toUpperCase()
  .trim();

return [{ json: { modelo_normalizado: normalizado } }];

